arguments.file_text:
// Test stackalloc with Span of native-sized integers (nint / nuint)

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

// stackalloc nint
Span<nint> signedSpan = stackalloc nint[5];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = i * 10;

Console.WriteLine("\nSpan<nint> via stackalloc:");
foreach (var val in signedSpan)
    Console.Write($"  {val}");
Console.WriteLine();

// stackalloc nuint
Span<nuint> unsignedSpan = stackalloc nuint[5];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 100);

Console.WriteLine("\nSpan<nuint> via stackalloc:");
foreach (var val in unsignedSpan)
    Console.Write($"  {val}");
Console.WriteLine();

// stackalloc with collection expression initializer
Span<nint> initialized = stackalloc nint[] { 42, -1, nint.MaxValue, nint.MinValue };
Console.WriteLine("\nInitialized Span<nint>:");
foreach (var val in initialized)
    Console.Write($"  {val}");
Console.WriteLine();

